node -e '
const t="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";
const H={Authorization:"Bearer "+t,"User-Agent":"ivx-deploy","Accept":"application/vnd.github+json"};
(async()=>{
  const r1=await fetch("https://api.github.com/user",{headers:H});
  const b1=await r1.json().catch(()=>({}));
  console.log("GH_USER_HTTP:"+r1.status+" login:"+(b1.login??null)+" scopes:"+(r1.headers.get("x-oauth-scopes")??"n/a"));
  const r2=await fetch("https://api.github.com/repos/ibb142/rork-global-real-estate-invest",{headers:H});
  const b2=await r2.json().catch(()=>({}));
  console.log("GH_REPO_HTTP:"+r2.status+" full:"+(b2.full_name??null)+" perms:"+JSON.stringify(b2.permissions??null)+" default_branch:"+(b2.default_branch??null));
})();
'

